action.command:
node -e "
const fs = require('fs');
let data = '';
process.stdin.on('data', chunk => data += chunk);
process.stdin.on('end', () => {
  const ctx = JSON.parse(data);
  const cmd = ctx.toolInput?.command || '';

  const dangerousPatterns = [
    /rm\\s+(-[rf]+|\\S+)\\s*$/i,
    /rm\\s+-[rf]*.*\\s+/i,
    /rm\\s+.*\\s+-[rf]/i,
    /rmdir\\s+/i,
    /dd\\s+if=/i,
    /mkfs/i,
    /fdisk/i,
    /:(){ :|:& };:/,
    /chmod\\s+(-R\\s+)?(000|777)/i,
    /chown\\s+(-R\\s+)?/i,
    />\\/dev\\/sd[a-z]/i,
    /wget.*\\|.*sh/i,
    /curl.*\\|.*sh/i,
    /\\bsudo\\s+rm\\b/i,
    /\\bsudo\\s+dd\\b/i,
    /\\bsudo\\s+mkfs\\b/i,
    /git\\s+push.*--force/i,
    /git\\s+reset\\s+--hard/i,
    /git\\s+clean\\s+-[fdx]/i,
    /drop\\s+(table|database)/i,
    /truncate\\s+table/i,
    /\\bsu\\s*$/i,
    /\\bsudo\\s+su\\b/i,
    /nc\\s+.*-e/i,
    /ncat\\s+.*-e/i
  ];

  const isDangerous = dangerousPatterns.some(p => p.test(cmd));

  if (isDangerous) {
    console.log(JSON.stringify({
      hookSpecificOutput: {
        permissionDecision: 'ask',
        permissionDecisionReason: 'This command matches a dangerous pattern. Please confirm you want to execute it.'
      }
    }));
  }
  process.exit(0);
});
"
